import React, { useState } from 'react';
import './InputForm.css';

const options = {
  risk_appetite: [
    { value: 'low', label: '🛡️ Low Risk', desc: 'Capital preservation, stable returns' },
    { value: 'medium', label: '⚖️ Medium Risk', desc: 'Balanced growth and safety' },
    { value: 'high', label: '🚀 High Risk', desc: 'Maximum growth potential' },
  ],
  time_horizon: [
    { value: 'short', label: '⚡ Short Term', desc: 'Less than 3 years' },
    { value: 'medium', label: '📅 Medium Term', desc: '3 to 7 years' },
    { value: 'long', label: '🌱 Long Term', desc: 'More than 7 years' },
  ],
  fund_type: [
    { value: 'equity', label: '📈 Equity', desc: 'Stocks-based, high growth' },
    { value: 'debt', label: '🔒 Debt', desc: 'Bonds-based, stable income' },
    { value: 'hybrid', label: '🔄 Hybrid', desc: 'Mix of equity & debt' },
    { value: 'index', label: '📊 Index', desc: 'Track market indices' },
  ],
  investment_type: [
    { value: 'lumpsum', label: '💰 Lumpsum', desc: 'One-time investment' },
    { value: 'sip', label: '📆 SIP', desc: 'Monthly systematic plan' },
    { value: 'both', label: '🔀 Both', desc: 'Lumpsum + SIP combo' },
  ],
};

export default function InputForm({ onSubmit }) {
  const [form, setForm] = useState({
    risk_appetite: '',
    time_horizon: '',
    fund_type: '',
    investment_type: '',
    investment_amount: 10000,
  });

  const [step, setStep] = useState(0);

  const steps = ['risk_appetite', 'time_horizon', 'fund_type', 'investment_type'];
  const stepLabels = ['Risk Appetite', 'Time Horizon', 'Fund Type', 'Investment Type'];

  const handleSelect = (field, value) => {
    setForm((prev) => ({ ...prev, [field]: value }));
  };

  const isComplete = steps.every((s) => form[s]);

  const handleSubmit = () => {
    if (!isComplete) return;
    onSubmit(form);
  };

  return (
    <div className="form-wrapper">
      <div className="form-hero">
        <h2>Build Your Investment Profile</h2>
        <p>Our AI agents will analyse 5,000+ mutual funds to find your perfect match</p>
      </div>

      <div className="progress-bar">
        {steps.map((s, i) => (
          <div
            key={s}
            className={`progress-step ${form[s] ? 'done' : ''} ${i === step ? 'active' : ''}`}
            onClick={() => setStep(i)}
          >
            <div className="progress-dot">{form[s] ? '✓' : i + 1}</div>
            <span>{stepLabels[i]}</span>
          </div>
        ))}
      </div>

      <div className="form-section">
        <h3>{stepLabels[step]}</h3>
        <div className="option-grid">
          {options[steps[step]].map((opt) => (
            <div
              key={opt.value}
              className={`option-card ${form[steps[step]] === opt.value ? 'selected' : ''}`}
              onClick={() => {
                handleSelect(steps[step], opt.value);
                if (step < steps.length - 1) setTimeout(() => setStep(step + 1), 300);
              }}
            >
              <div className="option-label">{opt.label}</div>
              <div className="option-desc">{opt.desc}</div>
            </div>
          ))}
        </div>
      </div>

      <div className="form-section amount-section">
        <h3>Investment Amount</h3>
        <div className="slider-wrapper">
          <input
            type="range"
            min="1000"
            max="1000000"
            step="1000"
            value={form.investment_amount}
            onChange={(e) => setForm((p) => ({ ...p, investment_amount: Number(e.target.value) }))}
            className="amount-slider"
          />
          <div className="amount-display">
            <span>₹</span>
            <strong>{form.investment_amount.toLocaleString('en-IN')}</strong>
          </div>
        </div>
        <div className="amount-labels">
          <span>₹1,000</span>
          <span>₹5L</span>
          <span>₹10L</span>
        </div>
      </div>

      {isComplete && (
        <div className="form-summary">
          <h3>Your Profile Summary</h3>
          <div className="summary-grid">
            {steps.map((s) => (
              <div key={s} className="summary-item">
                <span className="summary-label">{stepLabels[steps.indexOf(s)]}</span>
                <span className="summary-value">{form[s]}</span>
              </div>
            ))}
            <div className="summary-item">
              <span className="summary-label">Amount</span>
              <span className="summary-value">₹{form.investment_amount.toLocaleString('en-IN')}</span>
            </div>
          </div>
          <button className="submit-btn" onClick={handleSubmit}>
            <span>🤖 Get AI Recommendations</span>
            <span className="btn-sub">Powered by Agentic + Explainable AI</span>
          </button>
        </div>
      )}

      <div className="form-nav">
        {step > 0 && <button className="nav-btn" onClick={() => setStep(step - 1)}>← Back</button>}
        {step < steps.length - 1 && form[steps[step]] && (
          <button className="nav-btn primary" onClick={() => setStep(step + 1)}>Next →</button>
        )}
      </div>
    </div>
  );
}
